-- Case 05: DDL, COPY, MERGE, streams, and a task graph.
create or replace FILE FORMAT RAW.FF_EVENTS_JSON type = JSON COMPRESSION = AUTO STRIP_OUTER_ARRAY = false ALLOW_DUPLICATE = false IGNORE_UTF8_ERRORS = false REPLACE_INVALID_CHARACTERS = false SKIP_BYTE_ORDER_MARK = true comment = 'JSON Lines / 日本語・한국어・العربية';
create or replace FILE FORMAT RAW.FF_CUSTOMERS_CSV type = CSV COMPRESSION = AUTO FIELD_DELIMITER = ',' RECORD_DELIMITER = '\n' SKIP_HEADER = 1 FIELD_OPTIONALLY_ENCLOSED_BY = '"' ESCAPE_UNENCLOSED_FIELD = NONE TRIM_SPACE = True NULL_IF = ('', 'NULL', 'null', '\\N') EMPTY_FIELD_AS_NULL = True ENCODING = 'UTF8';
Create Or Replace Stage RAW.INGEST_STAGE Directory = (ENABLE = true, AUTO_REFRESH = False) ENCRYPTION = (Type = 'SNOWFLAKE_SSE') comment = 'Formatter E2E internal stage';
copy into RAW.CUSTOMER_CSV_LANDING (customer_id, display_name, locale, email, marketing_opt_in, source_filename, source_row_number, loaded_at) From (select $1::STRING, $2::STRING, $3::STRING, NULLIF(LOWER(TRIM($4::STRING)), ''), TRY_TO_BOOLEAN($5::STRING), METADATA$FILENAME, METADATA$FILE_ROW_NUMBER, METADATA$START_SCAN_TIME from @RAW.INGEST_STAGE/customers/ (File_Format => RAW.FF_CUSTOMERS_CSV)) pattern = '.*customers_[0-9]{8}\\.csv' ON_ERROR = 'CONTINUE' PURGE = false FORCE = false RETURN_FAILED_ONLY = false;
Copy Into RAW.EVENT_LANDING (event_id, event_time, event_type, payload, source_filename, file_content_key, loaded_at) From (select $1:event_id::STRING, TRY_TO_TIMESTAMP_TZ($1:event_time::STRING), $1:event_type::STRING, $1, METADATA$FILENAME, METADATA$FILE_CONTENT_KEY, METADATA$START_SCAN_TIME from @RAW.INGEST_STAGE/events/ (File_Format => RAW.FF_EVENTS_JSON)) FILES = ('events_ja.jsonl', 'events_global.jsonl') ON_ERROR = 'SKIP_FILE_10%' SIZE_LIMIT = 5368709120 PURGE = False;
merge into CORE.CUSTOMERS as target using (Select customer_id, display_name, locale, email, marketing_opt_in, source_filename, loaded_at, SHA2_HEX(CONCAT_WS('|', customer_id, COALESCE(display_name, '∅'), COALESCE(locale, 'und'), COALESCE(email, '∅'), COALESCE(marketing_opt_in::STRING, '∅')), 256) As row_hash From RAW.CUSTOMER_CSV_LANDING Qualify ROW_NUMBER() Over (partition by customer_id order by loaded_at desc, source_filename Desc) = 1) As source On target.customer_id = source.customer_id When Matched And target.row_hash <> source.row_hash then update set target.display_name = source.display_name, target.locale = source.locale, target.email = source.email, target.marketing_opt_in = source.marketing_opt_in, target.row_hash = source.row_hash, target.source_filename = source.source_filename, target.updated_at = CURRENT_TIMESTAMP() when not matched then insert (customer_id, display_name, locale, email, marketing_opt_in, row_hash, source_filename, created_at, updated_at) values (source.customer_id, source.display_name, source.locale, source.email, source.marketing_opt_in, source.row_hash, source.source_filename, CURRENT_TIMESTAMP(), CURRENT_TIMESTAMP());
Create Or Replace Stream RAW.EVENT_LANDING_STREAM On Table RAW.EVENT_LANDING APPEND_ONLY = False SHOW_INITIAL_ROWS = True Comment = 'CDC stream / 변경 스트림 / تدفق التغيير';
Create Or Replace Task OPS.TASK_PIPELINE_ROOT Warehouse = FORMATTER_TEST_WH Schedule = 'USING CRON 0 * * * * UTC' USER_TASK_TIMEOUT_MS = 1800000 SUSPEND_TASK_AFTER_NUM_FAILURES = 3 TASK_AUTO_RETRY_ATTEMPTS = 1 comment = 'Root task; intentionally left suspended after creation' As Insert Into OPS.PIPELINE_LOG (batch_id, step_name, status, message, logged_at) Select UUID_STRING(), 'TASK_ROOT', 'STARTED', 'Scheduled graph started', CURRENT_TIMESTAMP();
create or replace task OPS.TASK_APPLY_EVENTS warehouse = FORMATTER_TEST_WH after OPS.TASK_PIPELINE_ROOT when SYSTEM$STREAM_HAS_DATA('RAW.EVENT_LANDING_STREAM') as call OPS.SP_APPLY_EVENT_STREAM();
Create Or Replace Task OPS.TASK_REFRESH_MARTS Warehouse = FORMATTER_TEST_WH After OPS.TASK_APPLY_EVENTS As Call OPS.SP_REFRESH_MARTS();
create or replace task OPS.TASK_PIPELINE_FINALIZER warehouse = FORMATTER_TEST_WH finalize = OPS.TASK_PIPELINE_ROOT as insert into OPS.PIPELINE_LOG (batch_id, step_name, status, message, logged_at) select UUID_STRING(), 'TASK_FINALIZER', 'COMPLETED', 'Task graph finished / タスクグラフ完了', CURRENT_TIMESTAMP();
